"use strict";parserFactory.register("novelall.com",()=>new NovelAllParser);class NovelAllParser extends Parser{constructor(){super()}getChapterUrls(e){let t=[...e.querySelectorAll("ul.detail-chlist a")];return Promise.resolve(this.buildChapterList(t))}buildChapterList(e){return e.reverse().map(e=>({sourceUrl:e.href,title:e.getAttribute("title")}))}findContent(e){return e.querySelector("div.reading-box")}extractAuthor(e){let t=e.querySelector("a[href*='author']");return null==t?super.extractAuthor(e):t.textContent}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.manga-detailtop")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.manga-detailtop, div.manga-detailmiddle")]}cleanInformationNode(e){util.removeChildElementsMatchingSelector(e,"script")}}